// EXTRA LESSONS — MONEY & THE BIBLE  (add to course id: "bible-money")
// ═══════════════════════════════════════════════════════════════════════════
export const BIBLE_MONEY_EXTRA: Lesson[] = [
  {
    id: "lesson-contentment",
    title: "The Secret of Contentment",
    steps: [
      { type: "info", title: "The Most Counter-Cultural Financial Principle", content: "<p>Philippians 4:11–12 — <em>'I have learned, in whatever state I am, to be content... I know how to be abased, and I know how to abound.'</em></p><p>Contentment is a learned skill, not a natural state. In a consumer society built on manufactured dissatisfaction, contentment is financially revolutionary. A content person does not need to upgrade, impress, or consume to feel complete.</p>" },
      { type: "mcq", question: "According to Philippians 4, contentment is:", options: ["A natural personality trait you either have or don't", "A skill that Paul learned through experience in various circumstances", "Only possible when all your needs are met", "Incompatible with financial ambition"], correct: 1, feedback: { correct: "Paul says 'I have learned' — contentment is developed through practice, not inherited. This means it can be cultivated deliberately in your financial life.", incorrect: "'I have learned' — contentment is a learnable, practised skill. It's not a personality type or a life condition. Anyone can develop it." } },
      { type: "true-false", statement: "Biblical contentment means you should never set financial goals or aspire to improve your situation.", correct: false, feedback: { correct: "Correct — contentment is about your internal posture, not passive resignation. Proverbs praises the ant for preparing and planning. You can be content AND work diligently toward financial goals.", incorrect: "Contentment is an internal posture, not external passivity. The Bible praises diligent planning and hard work. You can pursue improvement while being content with where you are today." } },
      { type: "info", title: "Contentment and the Comparison Trap", content: "<p>Much of South Africa's consumer debt is driven by social comparison — buying things to match the perceived lifestyle of others. Galatians 6:4 says: <em>'Each one should test their own actions... without comparing themselves to someone else.'</em></p><p>Financial freedom begins when you stop measuring your worth by what others have. Their lifestyle is often debt-funded anyway.</p>" },
      { type: "scenario", question: "Your neighbour buys a new BMW X5. You feel pressure to upgrade your paid-off Toyota. A contentment-based response is:", options: ["Finance the BMW — you deserve it too", "Recognise the feeling as comparison-driven and evaluate based on your own goals, not their choices", "Feel guilty about your Toyota", "Avoid your neighbour until the feeling passes"], correct: 1, feedback: { correct: "Recognising the feeling as socially-triggered comparison (not genuine need) is the first step. Your paid-off Toyota puts you financially ahead of someone with a BMW payment every month.", incorrect: "Comparison-triggered spending is one of the primary wealth destroyers. A paid-off car with no monthly payment is always financially superior to a financed luxury vehicle." } },
    ] satisfies LessonStep[],
  },
  {
    id: "lesson-planning-proverbs",
    title: "Planning and Preparation in Proverbs",
    steps: [
      { type: "info", title: "God Honours Planning", content: "<p>Proverbs 24:27 — <em>'Put your outdoor work in order and get your fields ready; after that, build your house.'</em></p><p>The biblical principle: establish income sources before making commitments. Prepare the field (build your income, clear your debts) before building the house (major lifestyle commitments). This directly counters the SA tendency to take on lifestyle debt before financial foundations are established.</p>" },
      { type: "mcq", question: "Proverbs 24:27's principle of 'field before house' most directly applies to:", options: ["Only farmers", "Building income stability and clearing debt before taking on major financial commitments", "Always renting before buying", "Avoiding home ownership"], correct: 1, feedback: { correct: "The principle: establish income and financial foundation before expanding lifestyle commitments. It's the biblical order of operations — income first, then obligations.", incorrect: "Field before house = income/foundation before lifestyle obligations. Establish financial stability before taking on major commitments like home loans or luxury purchases." } },
      { type: "true-false", statement: "The Bible discourages long-term financial planning because we should trust God for tomorrow.", correct: false, feedback: { correct: "Correct — the Bible repeatedly praises forward planning (the ant, Joseph's 7-year grain storage, the virgins with oil). Trusting God and responsible planning are complementary, not opposites.", incorrect: "Planning is consistently praised in Scripture (Joseph, the ant, Proverbs 21:5). Trusting God for provision and planning wisely are not contradictory — they work together." } },
      { type: "info", title: "Proverbs 21:5 — Diligence vs Haste", content: "<p><em>'The plans of the diligent lead to profit as surely as haste leads to poverty.'</em></p><p>Two paths: diligent planning (thoughtful, consistent, patient) leads to profit. Hasty decisions (impulse spending, get-rich-quick schemes, reckless investment) leads to poverty. This proverb describes the mechanism behind most SA financial stories — both the successful and the ruined ones.</p>" },
      { type: "scenario", question: "Sipho is offered a 'limited time investment opportunity' promising to triple his money in 6 months. Proverbs 21:5 would counsel:", options: ["Invest immediately — God rewards boldness", "Slow down, plan carefully, investigate thoroughly before any decision", "Consult your pastor for a prophetic word", "Invest half and keep half as caution"], correct: 1, feedback: { correct: "Proverbs 21:5 directly contrasts diligent planning with haste leading to poverty. Urgency-based investment offers trigger the 'haste' warning. Always slow down, investigate, and verify.", incorrect: "Haste leads to poverty, diligence leads to profit. Any investment requiring urgent decision-making is triggering the haste warning from Proverbs. Slow down." } },
    ] satisfies LessonStep[],
  },
  {
    id: "lesson-work-ethic",
    title: "Work Ethic and Faithful Labour",
    steps: [
      { type: "info", title: "Work as Worship", content: "<p>Colossians 3:23 — <em>'Whatever you do, work at it with all your heart, as working for the Lord, not for human masters.'</em></p><p>Biblical work ethic transforms every job into an act of worship. The quality of your work, your reliability, your integrity — these become expressions of faith, not just professionalism. This principle creates the kind of excellence that naturally leads to financial advancement.</p>" },
      { type: "mcq", question: "Colossians 3:23 implies that Christians in the workplace should:", options: ["Work hard only when the boss is watching", "Work with full effort as if serving God directly, regardless of who is watching", "Prioritise church work over employment", "Avoid promotion as a sign of humility"], correct: 1, feedback: { correct: "Working 'as for the Lord' means consistent excellence regardless of oversight, politics, or perceived fairness. This integrity-based work ethic is both biblical and professionally effective.", incorrect: "Working for the Lord means full, consistent effort whether or not anyone is watching. This produces the kind of trustworthiness that creates career advancement opportunities." } },
      { type: "true-false", statement: "The Bible teaches that pursuing career advancement is spiritually problematic.", correct: false, feedback: { correct: "Correct — the Bible consistently commends diligence, skill development, and faithful service that leads to promotion. Proverbs 22:29 says the skilled worker will stand before kings.", incorrect: "Proverbs 22:29: 'A worker skilled in their craft will serve before kings.' The Bible commends developing skill and pursuing excellence. Advancement through integrity is honoured in Scripture." } },
      { type: "info", title: "Proverbs 22:29 — Skill and Advancement", content: "<p><em>'Do you see someone skilled in their work? They will serve before kings; they will not serve before officials of low rank.'</em></p><p>Investing in your professional skills, qualifications, and capabilities is a biblical financial principle — not just a career strategy. The diligent development of your gifts creates financial opportunity. This is why education and ongoing upskilling have biblical as well as economic justification.</p>" },
      { type: "scenario", question: "A Christian employee is offered overtime that would double her weekend income but misses church sometimes. The biblically balanced view is:", options: ["Never work overtime — Sunday is sacred", "All overtime is acceptable since work is worship", "Prayerfully balance rest, worship, family, and financial stewardship — no universal rule applies", "Prioritise overtime always — providing for family is worship"], correct: 2, feedback: { correct: "Scripture values rest (Sabbath), worship, family, and diligent work. Wise stewardship weighs all of these in context. There's no universal rule — prayerful discernment applies.", incorrect: "The Bible values Sabbath rest, corporate worship, family stewardship, and diligent work. Balancing these requires wisdom and prayer, not a rigid rule." } },
    ] satisfies LessonStep[],
  },
  {
    id: "lesson-avoiding-surety",
    title: "Avoiding Surety (Co-signing Debt)",
    steps: [
      { type: "info", title: "Proverbs on Co-signing Loans", content: "<p>Proverbs 11:15 — <em>'Whoever puts up security for a stranger will surely suffer, but whoever refuses to shake hands in pledge is safe.'</em></p><p>Proverbs 22:26-27 — <em>'Do not be one who shakes hands in pledge or puts up security for debts; if you lack the means to pay, your very bed will be snatched from under you.'</em></p><p>Co-signing (becoming surety) for another person's debt is consistently warned against in Proverbs. You become equally liable for the full debt.</p>" },
      { type: "mcq", question: "A close friend asks you to co-sign their car loan because their credit is poor. Proverbs teaches:", options: ["Loyalty to friends means always helping them financially", "Co-signing puts your own financial security at risk — Proverbs strongly warns against it", "Only co-sign for family, not friends", "Always co-sign to help others build credit"], correct: 1, feedback: { correct: "Proverbs repeatedly and clearly warns against co-signing. If the friend can't qualify alone, the bank has assessed them as unable to repay. You become equally liable.", incorrect: "Multiple Proverbs warn against surety (co-signing). A poor credit rating means the bank assesses them as unable to repay — and you take on that risk equally." } },
      { type: "true-false", statement: "In South Africa, co-signing a loan makes you jointly and severally liable for the full debt.", correct: true, feedback: { correct: "Correct — as co-signatory/surety, you are 100% liable for the debt. If the primary borrower stops paying, the lender can pursue YOU for the full amount, including through legal action and your assets.", incorrect: "Co-signing makes you jointly and severally liable. The lender can pursue you for the full amount if the borrower defaults — your savings, car, and income are at risk." } },
      { type: "info", title: "Helping Without Co-signing", content: "<p>If you want to help someone financially, biblical alternatives to co-signing:</p><ul><li>Give a gift or loan from your own savings — only what you can afford to lose</li><li>Help them improve their credit score legitimately over time</li><li>Help them save a deposit so they qualify on their own</li><li>Help them find a financial advisor who can guide debt rehabilitation</li></ul><p>Generosity is biblical — surety is warned against. These aren't the same thing.</p>" },
      { type: "scenario", question: "Your sibling needs R80,000 and asks you to co-sign a personal loan. You don't have R80,000 to give. The wisest response is:", options: ["Co-sign — family first", "Decline and explain why; offer to help in non-surety ways instead", "Ignore the request", "Tell them to ask someone else without explanation"], correct: 1, feedback: { correct: "Declining with explanation (biblical grounds + financial risk) preserves the relationship more than agreeing and later suffering financial harm. Offer non-surety alternatives.", incorrect: "Declining clearly and kindly with alternatives preserves both the relationship and your financial security. Co-signing puts both at risk." } },
    ] satisfies LessonStep[],
  },
  {
    id: "lesson-tithing",
    title: "Tithing and Financial Blessing",
    steps: [
      { type: "info", title: "Malachi 3:10 — The Test", content: "<p>Malachi 3:10 — <em>'Bring the whole tithe into the storehouse... Test me in this, says the Lord Almighty, and see if I will not throw open the floodgates of heaven and pour out so much blessing that there will not be room enough to store it.'</em></p><p>This is the only place in Scripture where God invites a test. The tithe (10% of income) is presented as both obedience and an invitation to experience God's provision firsthand.</p>" },
      { type: "mcq", question: "The word 'tithe' means:", options: ["A voluntary offering of any amount", "Exactly one-tenth (10%) of income", "Whatever you can afford above R100", "Only mandatory for church leaders"], correct: 1, feedback: { correct: "Tithe literally means 'tenth'. The biblical model is 10% of income given first — off the top, before other expenses. Offerings are separate, additional acts of generosity.", incorrect: "Tithe = tenth = 10%. It's a defined proportion given first. Offerings are voluntary amounts above the tithe." } },
      { type: "true-false", statement: "Tithing from income you've already taxed (your net salary) is a valid approach.", correct: true, feedback: { correct: "Correct — most financial advisors and biblical teachers agree that tithing on net income (after tax) is acceptable, as SARS has already claimed the gross portion. Some tithe on gross as an act of greater faith.", incorrect: "Tithing on net income is widely accepted as valid. The question of gross vs net is a personal conviction matter. Many tithe on net, some on gross — both are honoured approaches." } },
      { type: "info", title: "The Practical Mechanics of Tithing", content: "<p>For a R25,000/month net salary:</p><ul><li>10% tithe = R2,500/month</li><li>Set up an automatic debit order on payday — 'firstfruits' principle means tithe first</li><li>Account for it in your zero-based budget as the first line item, not the last</li></ul><p>Many South Africans who tithe report an unexplained sense of financial peace and order in their finances — beyond what the math should allow. Test it as Malachi invites.</p>" },
      { type: "fill-blank", title: "Tithe Calculation", prompt: "Your monthly net income is R32,000. A 10% tithe = R___.", correct: 3200, feedback: { correct: "R32,000 × 10% = R3,200/month. Budgeted as the first line item, before all other expenses — the 'firstfruits' principle.", incorrect: "R32,000 × 10% = R3,200/month. In a ZBB, this is the first allocation — not what's left after everything else." } },
    ] satisfies LessonStep[],
  },
  {
    id: "lesson-wealth-eternity",
    title: "Wealth and Eternity",
    steps: [
      { type: "info", title: "Storing Treasure in Heaven", content: "<p>Matthew 6:19-21 — <em>'Do not store up for yourselves treasures on earth, where moths and vermin destroy, and where thieves break in and steal. But store up for yourselves treasures in heaven... For where your treasure is, there your heart will be also.'</em></p><p>This is not a call to poverty — it's a call to eternal perspective. Building earthly wealth while also using it for eternal purposes (generosity, ministry, caring for others) is the integration of financial wisdom with spiritual maturity.</p>" },
      { type: "mcq", question: "Matthew 6:19-21 primarily teaches:", options: ["Christians should never save money", "Where you invest your money and heart reveals what you truly value", "Poverty is more spiritual than wealth", "Financial planning is incompatible with faith"], correct: 1, feedback: { correct: "Jesus points to where your treasure is as a diagnostic of your heart. The passage is about values and eternal perspective — not a prohibition on financial planning or saving.", incorrect: "Jesus identifies treasure location as a heart diagnostic. The passage is about what you ultimately value, not a prohibition on saving or wise financial management." } },
      { type: "true-false", statement: "Wealthy Christians in the Bible are always portrayed negatively.", correct: false, feedback: { correct: "Correct — Abraham, Job, Joseph of Arimathea, Lydia, and others are wealthy believers portrayed positively. The problem is never wealth itself but the love of money, idolatry of wealth, or withholding from those in need.", incorrect: "Abraham, Job, Joseph of Arimathea, and Lydia are wealthy believers portrayed with honour. Wealth is neutral — it's the heart posture toward it that Scripture evaluates." } },
      { type: "info", title: "1 Timothy 6:17-19 — Instructions to the Wealthy", content: "<p><em>'Command those who are rich in this present world not to be arrogant nor to put their hope in wealth, which is so uncertain, but to put their hope in God, who richly provides us with everything for our enjoyment. Command them to do good, to be rich in good deeds, and to be generous and willing to share...'</em></p><p>Paul doesn't tell the wealthy to give everything away. He instructs: humility, hope in God (not wealth), generosity, and good deeds. This is the biblical framework for stewarding financial success.</p>" },
      { type: "scenario", question: "A Christian businessman builds wealth over 20 years through diligence and integrity. He asks whether it's biblical to enjoy his success and also give generously. The biblical answer is:", options: ["Giving is required but enjoying wealth is spiritually dangerous", "Both are good — 1 Timothy 6:17 says God provides for our enjoyment; generosity is also commanded", "He should give everything away to remain humble", "Enjoyment is fine only if he tithes 10%"], correct: 1, feedback: { correct: "1 Timothy 6:17–18 gives both commands: enjoy what God has provided AND be generous. The biblical framework holds both in creative tension — not either/or.", incorrect: "1 Timothy 6:17 explicitly says God provides 'for our enjoyment'. Verse 18 commands generosity. Both are valid — not in tension but in integration." } },
    ] satisfies LessonStep[],
  },
  {
    id: "lesson-financial-integrity",
    title: "Financial Integrity",
    steps: [
      { type: "info", title: "Honest Scales in Business and Life", content: "<p>Proverbs 11:1 — <em>'Dishonest scales are an abomination to the Lord, but accurate weights are his delight.'</em></p><p>In modern application: honest business billing, accurate SARS declarations, transparent financial dealings with employers and clients, and fair treatment of staff. Financial integrity is not separate from faith — it is an expression of it.</p>" },
      { type: "mcq", question: "Proverbs 11:1 about 'honest scales' applies today to:", options: ["Only people who sell physical goods", "All financial dealings: accurate invoicing, honest tax declarations, fair pricing, transparent agreements", "Only business owners, not employees", "Primarily church finances"], correct: 1, feedback: { correct: "The principle of accurate weights (honest measurement) applies to all financial transactions: invoicing, tax, pricing, and agreements. Financial integrity is comprehensive, not selective.", incorrect: "'Honest scales' covers all financial dealings where you measure, report, or represent value: invoicing, tax, pricing, salary disclosure, financial reporting." } },
      { type: "true-false", statement: "A Christian employee who inflates business expenses to get a higher tax deduction is acting consistently with biblical financial principles.", correct: false, feedback: { correct: "Correct — inflating expense claims is dishonest. Romans 13:7 requires paying what is owed to authorities. Proverbs condemns dishonest weights in any form of financial transaction.", incorrect: "Inflating expenses = dishonest measurement = the exact opposite of 'accurate weights'. Romans 13:7 specifically requires paying what is owed to governing authorities." } },
      { type: "info", title: "Luke 16:10 — Integrity in Small Things", content: "<p><em>'Whoever can be trusted with very little can also be trusted with much, and whoever is dishonest with very little will also be dishonest with much.'</em></p><p>Financial integrity is built in small decisions: accurate timesheets, honest SARS returns, correct change returned, fair invoicing. These practices shape your character for larger financial responsibilities.</p>" },
      { type: "scenario", question: "Your employer overpays your salary by R3,000 due to a payroll error. A biblically-grounded response is:", options: ["Keep it — the error is their problem", "Spend it quickly before they notice", "Report it immediately to HR for correction", "Only tell them if they notice"], correct: 2, feedback: { correct: "Honest scales means returning what isn't yours, even when you could get away with keeping it. This is the integrity that builds trust and aligns financial behaviour with faith.", incorrect: "Report and return it. Keeping money you know isn't yours is dishonest regardless of who made the error. This is what integrity in small things looks like in practice." } },
    ] satisfies LessonStep[],
  },
  {
    id: "lesson-generosity-kingdom",
    title: "Generosity as Kingdom Strategy",
    steps: [
      { type: "info", title: "2 Corinthians 9:6-8 — Sowing and Reaping", content: "<p><em>'Whoever sows sparingly will also reap sparingly, and whoever sows generously will also reap generously. Each of you should give what you have decided in your heart to give, not reluctantly or under compulsion, for God loves a cheerful giver.'</em></p><p>Three principles: proportionality (generous sowing → generous reaping), intentionality (decide in your heart beforehand), and attitude (cheerful, not obligatory).</p>" },
      { type: "mcq", question: "2 Corinthians 9:7 says God loves a giver who gives:", options: ["The most money possible", "Reluctantly but faithfully", "Cheerfully, by their own decision", "Only in response to specific requests"], correct: 2, feedback: { correct: "The attitude matters as much as the amount. Cheerful, freely-chosen generosity — not reluctant compliance or social pressure. The heart behind the gift is seen by God.", incorrect: "Cheerful and self-decided generosity. Not reluctant. Not under compulsion. The heart posture is explicitly named as what God values." } },
      { type: "true-false", statement: "Biblical generosity is only about money given to church.", correct: false, feedback: { correct: "Correct — biblical generosity includes: giving to the poor (Proverbs 19:17), caring for widows and orphans (James 1:27), helping fellow believers in need (Acts 2:44-45), and giving to gospel workers. The 'storehouse' includes multiple expressions.", incorrect: "Generosity in Scripture extends to: the poor, widows, orphans, strangers, fellow believers, gospel workers, and community. The local church is one channel, not the only one." } },
      { type: "info", title: "Planning Your Giving", content: "<p>Intentional giving means deciding in advance what you'll give and to whom — not reactive, guilt-driven responses to every request. A giving plan might include:</p><ul><li>Tithe to local church: 10% off the top</li><li>Compassion fund: R500–R1,000/month for needs you encounter</li><li>Annual large gift: R5,000–R20,000 to a mission or cause</li></ul><p>'Decided in your heart' implies forethought, budgeting, and strategy — not spontaneous emotional response to pressure.</p>" },
      { type: "scenario", question: "You earn R40,000/month. You want to give 12% of income but feel financially stretched. The first step is:", options: ["Increase income before giving more", "Audit spending to find where 12% can come from within current budget", "Give 12% and trust God to cover the gap without a plan", "Reduce giving to 5% until comfortable"], correct: 1, feedback: { correct: "Intentional generosity starts with a spending audit — not just willpower. Finding R4,800 in a R40,000 budget requires knowing where the money currently goes. Budget first, then give with a plan.", incorrect: "Start with a spending audit. R4,800 in a R40k budget is 12% — but it requires knowing where current spending goes. Planned generosity needs a planned budget." } },
    ] satisfies LessonStep[],
  },
];

