// EXTRA LESSONS — MONEY PSYCHOLOGY  (add to course id: "money-psychology")
// ═══════════════════════════════════════════════════════════════════════════
export const PSYCHOLOGY_EXTRA: Lesson[] = [
  {
    id: "lesson-herd-mentality-fomo",
    title: "Herd Mentality & FOMO",
    steps: [
      { type: "info", title: "Why Everyone Buying Makes You Want to Buy Too", content: "<p>Herd mentality is the tendency to follow the crowd in financial decisions — buying what everyone else is buying (cryptocurrency in 2021, property in 2007) without independent analysis. FOMO (Fear of Missing Out) amplifies this: watching others' apparent gains creates urgency to join.</p><p>Both biases have caused more wealth destruction in SA than almost any other psychological trap.</p>" },
      { type: "mcq", question: "In 2021, everyone in your social circle is buying cryptocurrency. You have no knowledge of crypto. Herd-resistant behaviour is:", options: ["Buy immediately to not miss out", "Research independently, understand the asset, and only invest what you'd accept losing entirely", "Wait until the price doubles and then buy", "Copy exactly what your most successful friend bought"], correct: 1, feedback: { correct: "Independent research before any investment resists herd pressure. If you can't explain what you're buying and why, you're following the herd — not investing.", incorrect: "Herd resistance means independent analysis before action. Never invest in something you can't explain based on your own research." } },
      { type: "true-false", statement: "If an investment has been rising for 2 years and everyone is talking about it, it's usually the safest time to buy.", correct: false, feedback: { correct: "Correct — investments that have risen dramatically and reached mainstream media coverage are often near their peak. The herd arrived late. By the time 'everyone' is talking about it, early investors are often selling.", incorrect: "When an investment reaches mainstream coverage after a major rise, early investors are often exiting. 'When your taxi driver talks about it, it's time to sell' — a classic investing aphorism." } },
      { type: "info", title: "The Crypto FOMO Cycle in SA", content: "<p>Bitcoin cycles in SA perfectly illustrate FOMO investing:</p><ul><li>2020: Few people notice Bitcoin rising</li><li>Late 2021: Bitcoin near $69k, mainstream media coverage, FOMO peak</li><li>2022: Bitcoin falls 70%, FOMO buyers lose most of their investment</li><li>2023–24: Bitcoin recovers to new highs while 2021 FOMO buyers are still at a loss</li></ul><p>Those who bought based on FOMO in 2021 suffered; those who held through the cycle based on conviction eventually recovered. The difference was motivation: FOMO vs research.</p>" },
      { type: "scenario", question: "Your whole WhatsApp group made 50% returns on a particular investment last year. You feel pressure to join. The financially disciplined response is:", options: ["Join immediately — social proof is strong evidence", "Investigate independently: what is it, how does it work, what are the risks, is it FSCA-registered?", "Join with a small amount to reduce FOMO", "Ask the group admin what the minimum investment is"], correct: 1, feedback: { correct: "Independent investigation before any financial commitment is the only FOMO-resistant behaviour. Past group performance is not investment research.", incorrect: "Independent research is the only antidote to herd pressure. Past group returns tell you nothing about future performance or underlying risk." } },
    ] satisfies LessonStep[],
  },
  {
    id: "lesson-loss-aversion",
    title: "Loss Aversion",
    steps: [
      { type: "info", title: "Why Losses Hurt More Than Gains Feel Good", content: "<p>Loss aversion is the psychological phenomenon where losses feel approximately twice as painful as equivalent gains feel pleasurable. Losing R1,000 feels worse than gaining R1,000 feels good. This asymmetry drives irrational financial decisions: holding losing investments too long, selling winning investments too early, and paying excessive insurance for unlikely events.</p>" },
      { type: "mcq", question: "Your share investment falls 20%. Loss aversion would cause you to:", options: ["Rationally evaluate whether the business fundamentals have changed", "Feel disproportionate pain and be tempted to sell at the worst time", "See this as a buying opportunity", "Increase your monthly investment amount"], correct: 1, feedback: { correct: "Loss aversion creates urgency to stop the pain by selling — precisely at the worst time. Recognising this bias helps you pause and evaluate rationally before acting.", incorrect: "Loss aversion creates disproportionate emotional pain that drives premature selling at market lows. Recognising it is the first step to resisting it." } },
      { type: "true-false", statement: "Loss aversion is a sign of financial inexperience that disappears with more knowledge.", correct: false, feedback: { correct: "Correct — loss aversion is a hardwired psychological response, not a knowledge gap. Even professional investors experience it. The goal is to recognise and manage it, not eliminate it.", incorrect: "Loss aversion is hardwired into human psychology (it was an evolutionary survival mechanism). Even professional fund managers experience it. Recognition and systems help manage it." } },
      { type: "info", title: "Counteracting Loss Aversion", content: "<p>Strategies that help:</p><ul><li><strong>Automate investments:</strong> If the decision is made once (debit order), loss aversion can't intervene monthly</li><li><strong>Don't check portfolio daily:</strong> Less frequent observation reduces the emotional impact of short-term losses</li><li><strong>Write your investment thesis:</strong> When losses trigger fear, re-read why you invested — this engages rational thinking</li><li><strong>Use percentage framing:</strong> 'Down R50,000' sounds catastrophic; 'down 8%' is a normal fluctuation</li></ul>" },
      { type: "scenario", question: "Your R200,000 ETF portfolio drops to R160,000 (−20%) during a market correction. Loss aversion is pushing you to sell. The evidence-based rational question to ask first is:", options: ["How do I stop this loss?", "Have the underlying businesses I'm invested in fundamentally changed, or is this a market-wide temporary correction?", "Should I move everything to cash to feel safe?", "What would my friends do in this situation?"], correct: 1, feedback: { correct: "Separating market price from business fundamentals is the critical question. A 20% market-wide drop with unchanged business fundamentals is a buying opportunity, not a reason to sell.", incorrect: "The critical question: have fundamentals changed or is this temporary market noise? A 20% drop in a healthy ETF during a broad correction is historically a buying signal, not a selling signal." } },
    ] satisfies LessonStep[],
  },
  {
    id: "lesson-hedonic-adaptation",
    title: "Hedonic Adaptation",
    steps: [
      { type: "info", title: "Why More Never Feels Like Enough", content: "<p>Hedonic adaptation is the psychological process by which we quickly return to a stable level of happiness regardless of positive or negative events. You buy the new car and feel amazing for 3 months — then it becomes the normal car you barely notice. You upgrade your apartment — within months it's just home.</p><p>This mechanism drives perpetual lifestyle inflation: always upgrading, always chasing the next happiness boost, never building lasting wealth.</p>" },
      { type: "mcq", question: "After receiving a promotion and salary increase, most people report that within 6 months they:", options: ["Have significantly more financial security", "Feel the same day-to-day happiness as before the raise despite higher income", "Have dramatically reduced their stress about money", "Have more life satisfaction permanently"], correct: 1, feedback: { correct: "Hedonic adaptation returns people to their baseline happiness level within months. The promotion feels amazing — briefly. Then it becomes the new normal and the cycle restarts.", incorrect: "Research consistently shows that within 6 months of a significant positive income change, people return to near their baseline happiness. The 'high' is temporary." } },
      { type: "true-false", statement: "Buying experiences tends to provide more lasting satisfaction than buying material possessions, according to research.", correct: true, feedback: { correct: "Correct — research consistently shows that experiences (travel, shared activities, skill development) generate more lasting satisfaction than material purchases. Experiences can't become 'old' in the same way objects do.", incorrect: "Experiences resist hedonic adaptation better than possessions. A holiday memory grows richer over time; a purchased item quickly becomes background furniture." } },
      { type: "info", title: "Using Hedonic Adaptation for Wealth", content: "<p>You can harness hedonic adaptation in your favour:</p><ul><li>After a raise, invest the increase immediately before you adapt your lifestyle to it</li><li>You'll adapt to the higher investment level and it becomes your new normal too</li><li>Delayed upgrading: wait 3 months after wanting something. By then, adaptation means the desire has often passed</li><li>'Experience budgets' give lasting joy; 'object budgets' often don't</li></ul>" },
      { type: "scenario", question: "You receive a R6,000/month raise. Hedonic adaptation suggests that if you spend it all, within how many months will you feel 'normal' again with the higher lifestyle?", options: ["It never normalises", "About 3–6 months", "About 2 years", "Immediately"], correct: 1, feedback: { correct: "Research shows 3–6 months for most people to adapt to a new income level. This means the 'luxury' becomes necessity very quickly — which is why saving the raise before adapting to it is the key window.", incorrect: "Hedonic adaptation to new income levels typically happens within 3–6 months. After that, the new lifestyle feels just as normal as the old one — and the raise no longer feels like a raise." } },
    ] satisfies LessonStep[],
  },
  {
    id: "lesson-mental-accounting",
    title: "Mental Accounting",
    steps: [
      { type: "info", title: "How We Treat Money Differently Based on Its Source", content: "<p>Mental accounting is the tendency to treat money differently depending on where it came from or what we mentally label it. A tax refund feels like 'free money' and is spent impulsively. Regular salary is budgeted carefully. But R10,000 is R10,000 regardless of whether it came from SARS, a bonus, or a gift.</p><p>Mental accounting causes people to simultaneously: spend casino winnings frivolously, keep debt at 22% interest while holding savings at 5%, or invest a bonus but not regular income.</p>" },
      { type: "mcq", question: "You receive a R15,000 SARS tax refund. Mental accounting would cause you to:", options: ["Treat it identically to your monthly salary", "Spend it on a luxury because it feels like found money", "Immediately invest it per your financial plan", "Put it toward highest-interest debt"], correct: 1, feedback: { correct: "Mental accounting makes a refund feel like unexpected 'bonus' money — not real money requiring the same discipline as a salary. This leads to impulsive spending on what feels justified as a reward.", incorrect: "Mental accounting labels the refund as 'found money' distinct from earned salary. This reduces spending discipline. A refund is real money that should be treated identically to salary." } },
      { type: "true-false", statement: "Keeping money in separate accounts for different goals (sinking funds) is a form of beneficial mental accounting.", correct: true, feedback: { correct: "Correct — strategic mental accounting through separate accounts creates positive spending discipline. Knowing a specific amount is 'the holiday fund' prevents it being spent on something else.", incorrect: "Deliberate mental accounting through separate accounts is highly beneficial. Labelling money for specific purposes creates spending discipline and goal clarity." } },
      { type: "info", title: "The Simultaneous Debt and Savings Trap", content: "<p>A classic mental accounting error: keeping R30,000 in a savings account earning 7% while carrying R30,000 in credit card debt at 22%. The logic: 'I can't touch my savings — those are for emergencies.' But you're losing 15% net by holding both simultaneously.</p><p>The rational action: use savings to clear 22% debt, then rebuild savings at 7%. The emergency fund is rebuilt at 7% instead of costing you 15%.</p>" },
      { type: "scenario", question: "Zanele has R25,000 emergency fund earning 9% and R20,000 credit card debt at 21%. She refuses to use emergency savings to clear the card because 'those are separate'. The net annual cost of this mental accounting:", options: ["R0 — it's psychologically important to keep them separate", "≈R2,400/year net (she earns R2,250 on savings while paying R4,200 in credit card interest)", "It's beneficial — the safety of savings outweighs the interest cost", "Impossible to calculate"], correct: 1, feedback: { correct: "R20,000 × 21% = R4,200 credit card interest. R25,000 × 9% = R2,250 savings interest. Net cost of keeping both: R4,200 − R2,250 = R1,950/year for the mental accounting comfort of 'separate money'.", incorrect: "Credit card cost: R4,200/year. Savings earnings: R2,250/year. Net mental accounting cost: ≈R1,950/year. Use savings to clear debt, rebuild savings — don't pay 21% for 9% 'security'." } },
    ] satisfies LessonStep[],
  },
  {
    id: "lesson-confirmation-bias",
    title: "Confirmation Bias in Investing",
    steps: [
      { type: "info", title: "Seeing Only What You Want to See", content: "<p>Confirmation bias is the tendency to seek out and give more weight to information that confirms your existing beliefs, while ignoring or dismissing information that challenges them. In investing, it causes investors to: only read positive news about assets they own, dismiss valid warnings as 'fake news', and hold failing investments far too long.</p>" },
      { type: "mcq", question: "You own shares in a SA retail company. You read two analyst reports: one bullish, one bearish. Confirmation bias would cause you to:", options: ["Carefully weigh both reports equally", "Focus more on the bullish report and dismiss the bearish one as poorly researched", "Immediately sell based on the bearish report", "Show both reports to your financial advisor for guidance"], correct: 1, feedback: { correct: "Confirmation bias selectively amplifies information that validates current positions and minimises or explains away contradictory evidence.", incorrect: "Confirmation bias causes investors to weight confirming information higher than contradicting information — regardless of quality." } },
      { type: "true-false", statement: "Confirmation bias is more dangerous when you have a lot of money invested in an asset.", correct: true, feedback: { correct: "Correct — the more invested, the stronger the emotional pressure to confirm your decision was right. High-stake investments amplify confirmation bias, making it harder to evaluate objectively.", incorrect: "Larger positions amplify confirmation bias — the emotional need to be 'right' increases with the size of the bet. This is why position sizing matters for disciplined investing." } },
      { type: "info", title: "The Pre-Mortem Technique", content: "<p>A powerful antidote to confirmation bias: the pre-mortem. Before making an investment, ask: 'If this investment fails completely in 3 years, what will have been the reasons?' Then actively research those failure scenarios.</p><p>This forces you to look for disconfirming evidence — exactly what confirmation bias prevents you from doing naturally.</p>" },
      { type: "scenario", question: "You're considering investing R50,000 in a local restaurant business. Your friend is the owner and says it's doing great. Confirmation bias risk is highest when:", options: ["You review 3 years of audited financial statements", "You only speak to the friend and read the social media page", "You survey competitors and the local market", "You consult an independent business analyst"], correct: 1, feedback: { correct: "Relying only on the seller's own narrative provides exclusively confirming information. Confirmation bias is greatest when your information sources are filtered through someone who wants you to invest.", incorrect: "Getting information only from the person seeking your investment is a confirmation bias trap. They present confirming evidence only. Seek independent, contradicting information deliberately." } },
    ] satisfies LessonStep[],
  },
  {
    id: "lesson-social-media-money-pressure",
    title: "Social Media and Money Pressure",
    steps: [
      { type: "info", title: "The Curated Wealth Illusion", content: "<p>Social media presents a curated highlight reel of financial success: luxury holidays, expensive cars, designer brands, exotic meals. What's hidden: the debt behind the lifestyle, the credit card statements, the anxiety about maintaining appearances.</p><p>Research shows social media exposure to high-status content directly increases spending in categories shown — particularly fashion, food, and travel.</p>" },
      { type: "mcq", question: "A friend posts frequent Instagram photos of luxury holidays and expensive restaurants. The financially accurate assumption is:", options: ["They're earning significantly more than you", "They're very good at investing and travel cheaply", "The lifestyle may be partly or fully debt-funded — you can't tell from photos", "They must be in a high-paying industry"], correct: 2, feedback: { correct: "Social media shows spending, not net worth. The luxury holiday may be on a credit card. The expensive car may be financed at 16%. You cannot assess someone's financial health from their social media posts.", incorrect: "Social media shows spending, not financial health. Luxury displays are often debt-funded. Net worth and Instagram posts have no reliable correlation." } },
      { type: "true-false", statement: "Unfollowing or muting accounts that trigger comparison-spending impulses is a financially beneficial action.", correct: true, feedback: { correct: "Correct — reducing exposure to status-display content reduces the social comparison mechanism that drives spending. Curating your feed is a legitimate financial wellness strategy.", incorrect: "Curating your information environment is a genuine financial wellness tool. Less exposure to comparative status content reduces the emotional spending trigger it creates." } },
      { type: "info", title: "The 'Stealth Wealth' Alternative", content: "<p>Research on genuinely wealthy people (The Millionaire Next Door, Stop Acting Rich) consistently finds: most wealthy people drive average cars, live in modest neighbourhoods, shop at ordinary stores, and avoid conspicuous consumption.</p><p>Wealth and the display of wealth are strongly negatively correlated at the high end. Those who look the wealthiest on social media are often the least wealthy in reality.</p>" },
      { type: "scenario", question: "You feel genuinely depressed after 30 minutes of Instagram browsing because others seem to have more. The most evidence-based response is:", options: ["Work harder to earn more to match their lifestyle", "Spend more to feel better temporarily", "Recognise the curated nature of what you're seeing and audit whether these accounts are benefiting your financial mindset", "Take a break but return to normal usage after"], correct: 2, feedback: { correct: "The feeling of inadequacy is the designed output of status-display content. Recognising it, auditing its effect on your spending impulses, and potentially reducing exposure is the financial wellness-based response.", incorrect: "Social media comparison depression followed by spending is a predictable cycle. Recognising the manipulation and adjusting your information diet is the evidence-based response." } },
    ] satisfies LessonStep[],
  },
];

