// EXTRA LESSONS — RETIREMENT PLANNING  (add to course id: "retirement")
// ═══════════════════════════════════════════════════════════════════════════
export const RETIREMENT_EXTRA: Lesson[] = [
  {
    id: "lesson-ra-vs-pension-comparison",
    title: "RA vs Pension Fund: Key Differences",
    steps: [
      { type: "info", title: "Three Retirement Vehicle Types", content: "<p><strong>Pension Fund:</strong> Employer-sponsored. Both contribute. At retirement: 1/3 lump sum, 2/3 annuity. At resignation: transfer or cash out. Employer must offer it if they have one.</p><p><strong>Provident Fund:</strong> Same structure, aligned with pension fund rules from 2024 onward.</p><p><strong>Retirement Annuity (RA):</strong> Private. No employer link. You choose the provider and contribution amount. Accessible only from age 55. Ideal for self-employed or supplementing employer fund.</p>" },
      { type: "mcq", question: "What is the main advantage of an RA over a workplace pension fund?", options: ["Higher contribution limits", "Portability and independence from employment status", "Earlier access before age 55", "Tax-free withdrawals at any age"], correct: 1, feedback: { correct: "An RA is not linked to employment — it moves with you through job changes, career breaks, and self-employment. It provides continuity of retirement saving regardless of employment changes.", incorrect: "Portability is the RA's key advantage. Unlike a pension fund that's employer-dependent, an RA belongs to you and continues regardless of employment status." } },
      { type: "true-false", statement: "You can contribute to both an employer pension fund AND a personal RA simultaneously.", correct: true, feedback: { correct: "Correct — and this is often recommended. The combined 27.5% deduction limit applies to the total of all retirement fund contributions. Many SA employees contribute to their employer fund AND an additional RA.", incorrect: "Both simultaneously is not only allowed but often recommended. The 27.5% limit applies to combined contributions across all retirement vehicles." } },
      { type: "info", title: "When to Use an RA vs Rely on Pension Fund", content: "<ul><li><strong>Rely on pension fund only:</strong> If employer contributes 7.5%+ and you're fully utilising the employer match</li><li><strong>Add an RA:</strong> If you want to maximise the 27.5% limit beyond what your employer fund allows</li><li><strong>RA as primary:</strong> If self-employed, freelancing, or your employer has no retirement fund</li></ul>" },
      { type: "fill-blank", title: "Contribution Limit Check", prompt: "You earn R60,000/month (R720,000/year). Maximum total retirement fund deduction per year = 27.5% of R720,000 = R___ (nearest rand).", correct: 198000, feedback: { correct: "R720,000 × 27.5% = R198,000/year maximum deductible retirement contributions. Your employer + employee pension + RA contributions combined should not exceed this for maximum tax efficiency.", incorrect: "R720,000 × 27.5% = R198,000/year — the maximum combined deductible retirement contribution across all retirement vehicles." } },
    ] satisfies LessonStep[],
  },
  {
    id: "lesson-retirement-age",
    title: "Choosing When to Retire",
    steps: [
      { type: "info", title: "Earlier Isn't Always Better", content: "<p>Retiring at 55 vs 65 has a dramatic impact on your required retirement capital. At 55 you need 35–40 years of income (to age 90–95). At 65 you need 25–30 years. Retiring 10 years earlier requires approximately 50% more saved capital to sustain the same lifestyle at the same drawdown rate.</p>" },
      { type: "mcq", question: "Why does retiring 10 years earlier require approximately 50% more capital?", options: ["You pay more tax on early retirement", "You need more years of income AND lose 10 years of investment growth on your portfolio", "Inflation is higher in early retirement", "Medical costs increase in early retirement"], correct: 1, feedback: { correct: "Two compounding factors: (1) your portfolio misses 10 years of growth at 10% (enormous), and (2) you need 10 more years of withdrawals. Together these require roughly 50% more capital.", incorrect: "Early retirement costs doubly: (1) portfolio misses 10 years of compound growth, (2) you need 10 more years of drawdown. Both factors compound to require ~50% more capital." } },
      { type: "true-false", statement: "Working part-time in early retirement (semi-retirement) can significantly reduce the capital required.", correct: true, feedback: { correct: "Correct — even R10,000–R15,000/month from part-time work reduces portfolio drawdown by R120,000–R180,000/year. This preserves capital dramatically and extends the fund's life.", incorrect: "Semi-retirement income dramatically reduces required drawdown. Even modest part-time income of R10,000/month saves R120,000/year from the portfolio — extending its life by years." } },
      { type: "info", title: "The Financial Independence Number", content: "<p>Financial independence (not just retirement) is when your passive income from investments covers all living expenses. Using the 4% rule:</p><ul><li>Living expenses: R30,000/month = R360,000/year</li><li>Capital needed: R360,000 ÷ 4% = R9 million</li><li>At R9 million in investments, you can stop working — at any age</li></ul><p>The FI number can be reached much earlier than traditional retirement age with high savings rates (50%+ of income).</p>" },
      { type: "scenario", question: "Thando, 45, has R4 million invested, earns R60,000/month, and lives on R30,000/month. Using the 4% rule, she needs R9 million to be financially independent. She currently saves R30,000/month at 10% return. Approximately how many more years to reach R9 million from R4 million:", options: ["5 years", "About 7 years", "About 12 years", "About 15 years"], correct: 1, feedback: { correct: "R4 million growing at 10% + R30,000/month contributions reaches approximately R9 million in about 7 years. At 52, Thando achieves financial independence.", incorrect: "R4m at 10% + R30k/month reaches ≈R9m in approximately 7 years. Starting with a significant base dramatically accelerates the timeline." } },
    ] satisfies LessonStep[],
  },
  {
    id: "lesson-annuity-types",
    title: "Understanding Annuity Types",
    steps: [
      { type: "info", title: "The Big Choice at Retirement", content: "<p>At retirement, you must convert your retirement savings into income. Two primary choices:</p><p><strong>Guaranteed (life) annuity:</strong> Fixed monthly income for life, regardless of how long you live. No investment risk. Income never runs out. Non-negotiable — you can't change it once purchased.</p><p><strong>Living annuity:</strong> You remain invested. Draw 2.5–17.5% per year. Flexible income. Investment risk stays with you. Can run out. Remaining capital passes to heirs.</p>" },
      { type: "mcq", question: "Which type of annuity eliminates longevity risk (the risk of outliving your money)?", options: ["Living annuity at 4% drawdown", "Guaranteed life annuity", "Money market fund at retirement", "Balanced unit trust"], correct: 1, feedback: { correct: "A guaranteed life annuity pays a fixed income for as long as you live — even to age 100. This completely eliminates longevity risk, though at the cost of flexibility and estate value.", incorrect: "A guaranteed life annuity pays for life regardless of how long you live — the insurance company bears the longevity risk, not you." } },
      { type: "true-false", statement: "A living annuity income is guaranteed not to run out.", correct: false, feedback: { correct: "Correct — a living annuity can be depleted if the drawdown rate exceeds investment returns over time. At 15% drawdown on 8% returns, the fund depletes in approximately 12 years.", incorrect: "Living annuities CAN run out. If drawdown (e.g., 15%) exceeds returns (e.g., 8%), capital depletes. The fund offers no lifetime income guarantee." } },
      { type: "info", title: "The Hybrid Approach", content: "<p>Many SA retirement advisors recommend a hybrid strategy:</p><ul><li>Use guaranteed annuity to cover essential monthly expenses (rent/bond, food, utilities, medical aid)</li><li>Use living annuity for discretionary spending and estate planning</li></ul><p>This gives: longevity certainty for basics (guaranteed) + flexibility for extras + potential estate value (living). The Sanlam 'annuity umbrella' and similar products offer this structure.</p>" },
      { type: "scenario", question: "Nomsa, 65, retires with R5 million. Her essential expenses: R18,000/month. Discretionary: R8,000/month. A hybrid approach would be:", options: ["Put everything in a living annuity at 6%", "Put R3m in guaranteed annuity (covering R18k/month) and R2m in living annuity (for R8k discretionary)", "Put everything in guaranteed annuity", "Keep everything in cash earning 9%"], correct: 1, feedback: { correct: "R3m in guaranteed annuity provides reliable R18k/month for life. R2m in living annuity at 5% provides R8,300/month discretionary with growth potential and estate value.", incorrect: "Hybrid: guaranteed for essentials (certainty of income), living for discretionary (flexibility + growth + estate). This balances security with flexibility." } },
    ] satisfies LessonStep[],
  },
  {
    id: "lesson-post-retirement-healthcare",
    title: "Healthcare Planning in Retirement",
    steps: [
      { type: "info", title: "The Biggest Retirement Expense Nobody Plans For", content: "<p>Healthcare is consistently the most underestimated retirement cost. A couple retiring at 65 can expect to spend R3,000–R8,000/month on medical aid and gap cover — and this cost increases faster than general inflation (medical inflation runs 8–12% per year vs CPI of 4–6%).</p><p>Over 25 years of retirement, healthcare costs for a couple can exceed R5–10 million in total.</p>" },
      { type: "mcq", question: "Medical inflation (the rate at which healthcare costs increase) in SA typically:", options: ["Matches general CPI inflation", "Runs below CPI due to medical advances", "Runs 2–6% above CPI annually", "Is fixed by law at 5%"], correct: 2, feedback: { correct: "Medical inflation in SA typically runs 2–6% above CPI. A medical aid premium of R5,000/month today becomes R13,000–R22,000/month in 25 years depending on the rate.", incorrect: "Medical inflation runs 2–6% above CPI in SA. This medical cost escalation must be factored into retirement planning — it erodes purchasing power faster than general inflation." } },
      { type: "true-false", statement: "Most retirees can drop medical aid to save money once they're no longer working.", correct: false, feedback: { correct: "Correct — medical aid is MORE critical in retirement, not less. Without employer group rates, individual medical aid is more expensive. Healthcare usage increases with age. Dropping cover is extremely risky.", incorrect: "Healthcare usage increases sharply in retirement. Without employer group cover, individual rates are higher. Dropping medical aid in retirement creates catastrophic financial risk." } },
      { type: "info", title: "The Late Joiner Penalty", content: "<p>Medical aid schemes apply a 'late joiner penalty' to members who join after age 35 without continuous previous medical aid membership. The penalty can be up to 75% of premium added permanently to your monthly contribution.</p><p>Maintain continuous medical aid from your first job — even a basic hospital plan. Gaps in coverage create late joiner penalties that follow you for life.</p>" },
      { type: "fill-blank", title: "Healthcare Retirement Provision", prompt: "A couple's medical aid costs R5,500/month now and escalates at 9%/year. After 20 years in retirement, monthly cost ≈ R___ (nearest thousand). Use: R5,500 × (1.09^20) ≈ R5,500 × 5.6.", correct: 30800, feedback: { correct: "R5,500 × 5.6 = R30,800/month in healthcare costs at year 20 of retirement. This is why healthcare inflation must be specifically budgeted in any retirement plan.", incorrect: "R5,500 × (1.09)^20 ≈ R5,500 × 5.6 ≈ R30,800/month. Medical inflation compounds relentlessly — plan for it explicitly." } },
    ] satisfies LessonStep[],
  },
  {
    id: "lesson-estate-planning-retirement",
    title: "Estate Planning at Retirement",
    steps: [
      { type: "info", title: "Your Estate Plan Must Be Retirement-Ready", content: "<p>At retirement, several estate planning elements become urgent:</p><ul><li>Updated will (beneficiaries may have changed)</li><li>Beneficiary nominations on all retirement funds and life policies (bypass estate)</li><li>Power of attorney for financial affairs (if you become incapacitated)</li><li>Living will (medical wishes)</li><li>Trust consideration (for estate duty reduction and minor beneficiary protection)</li></ul>" },
      { type: "mcq", question: "A beneficiary nomination on a retirement fund bypasses the estate because:", options: ["It's illegal to tax retirement fund payouts", "The Pension Funds Act allows trustees to pay directly to nominees, bypassing executor and estate duty in many cases", "Retirement funds are always tax-free on death", "SARS doesn't track retirement fund death benefits"], correct: 1, feedback: { correct: "Retirement fund death benefits are distributed by the fund trustees to beneficiaries and dependants — not necessarily through the estate. This avoids executor fees (3.5% + VAT) and speeds up payout to dependants.", incorrect: "Retirement funds pay through trustees to nominees/dependants — often bypassing the estate entirely. This avoids executor fees and estate administration delays." } },
      { type: "true-false", statement: "A living annuity at retirement passes to your heirs when you die.", correct: true, feedback: { correct: "Correct — unlike a guaranteed life annuity (which stops paying on death, or continues to a surviving spouse briefly), a living annuity preserves the remaining capital for beneficiaries or continuing income for a surviving spouse.", incorrect: "Living annuities pass remaining capital to beneficiaries. This is a key estate planning advantage over guaranteed annuities, which typically have no residual value on death." } },
      { type: "info", title: "Estate Duty in South Africa", content: "<p>Estate duty is 20% on the net estate above R3.5 million (25% on amounts above R30 million). A R5 million estate: R5m − R3.5m = R1.5m × 20% = R300,000 estate duty.</p><p>Life insurance payable to a spouse or beneficiary (not the estate) is exempt. Retirement fund benefits paid to dependants are also often exempt. Structure payouts correctly to minimise estate duty.</p>" },
      { type: "scenario", question: "You have a R8 million estate at death. Estate duty applies to R4.5 million above the abatement (R3.5m). Estate duty = R4.5m × 20% = R___ that SARS claims from your estate before heirs receive anything.", options: ["R200,000", "R900,000", "R1,600,000", "R300,000"], correct: 1, feedback: { correct: "R8m − R3.5m abatement = R4.5m × 20% = R900,000 in estate duty. Plus executor fees on the full estate. Proper estate planning reduces both significantly.", incorrect: "R4.5m × 20% = R900,000 in estate duty. Plus executor fees of approximately 3.5% + VAT on R8m = R310,000. Proper estate planning can reduce both." } },
    ] satisfies LessonStep[],
  },
];

